using UnityEngine;

/// <summary>
/// Objecto "só visível com Visão Nocturna" (P8 — Coruja H2, hasVision):
///
/// - Por defeito é INVISÍVEL (alpha 0) e INTANGÍVEL para o player — a
///   colisão entre os <see cref="colliders"/> deste objecto e o player é
///   ignorada (Physics2D.IgnoreCollision), porque um objecto invisível não
///   deve bloquear o caminho. Continua sólido para tudo o resto (inimigos,
///   blocos, etc.).
/// - Quando a NightVisionAbility está activa e o player está dentro do raio
///   (form.nightVisionRadius), o objecto aparece com FADE (alpha sobe
///   gradualmente até 'visibleAlpha' — um tom translúcido/"raio-X").
/// - Se <see cref="temColisaoAoRevelar"/> estiver activo (por defeito sim),
///   ao ficar revelado o objecto passa a colidir normalmente com o player
///   (ex: plataforma/parede secreta que se torna sólida ao ser vista). Se
///   estiver desactivado, o objecto continua "fantasma" mesmo revelado (ex:
///   pista/decoração puramente visual, sem efeito de jogo).
/// - Para evitar um "pop" físico, se o player estiver sobreposto ao(s)
///   collider(es) no momento em que a colisão deveria ser reactivada, a
///   reactivação é adiada até deixarem de se sobrepor (verificado a cada
///   frame em Update).
/// - Ao desactivar a visão nocturna (ou o player saír do raio), faz FADE OUT
///   até alpha 0 e a colisão volta a ser ignorada (intangível/invisível).
///
/// Requer um SpriteRenderer. O Collider2D é opcional — se não houver, só o
/// fade visual é aplicado (sem alterar colisões).
/// </summary>
[RequireComponent(typeof(SpriteRenderer))]
public class NightVisionRevealable : MonoBehaviour
{
    [Tooltip("Alpha quando totalmente revelado (translúcido). 0 = invisível, 1 = opaco.")]
    [Range(0f, 1f)] public float visibleAlpha = 0.6f;

    [Tooltip("Velocidade do fade (variação de alpha por segundo).")]
    public float fadeSpeed = 2f;

    [Tooltip("Se activo, este objecto passa a colidir normalmente com o player quando revelado (ex: plataforma/parede secreta que se torna sólida). Se desactivo, continua sem colisão mesmo revelado (ex: decoração/pista puramente visual).")]
    public bool temColisaoAoRevelar = true;

    [Tooltip("Collider(es) deste objecto cuja colisão com o player é controlada por este script. Se vazio, tenta usar os Collider2D no próprio objecto.")]
    public Collider2D[] colliders;

    [SerializeField] private SpriteRenderer spriteRenderer;

    private float targetAlpha;
    private Collider2D playerCollider;

    /// <summary>Estado de colisão actualmente aplicado via Physics2D.IgnoreCollision (true = ignorada, player atravessa).</summary>
    private bool ignoringPlayerCollision;

    /// <summary>Estado de colisão pretendido — pode diferir de "ignoringPlayerCollision" enquanto a reactivação está adiada (ver TryApplyPlayerCollision).</summary>
    private bool desiredIgnore = true;

    /// <summary>true enquanto o objecto está (ou a ficar) visível para o player.</summary>
    public bool IsRevealed { get; private set; }

    private void Awake()
    {
        if (spriteRenderer == null) spriteRenderer = GetComponent<SpriteRenderer>();

        if (colliders == null || colliders.Length == 0)
            colliders = GetComponents<Collider2D>();

        // Começa invisível.
        var c = spriteRenderer.color;
        c.a = 0f;
        spriteRenderer.color = c;
        targetAlpha = 0f;
    }

    private void Start()
    {
        // Tarefa #3: por defeito (invisível) o objecto deve ser intangível
        // para o player — sem isto, um objecto ainda não revelado continua
        // a bloquear o caminho mesmo sem se ver. Procuramos o collider do
        // player aqui (em vez de esperar pela primeira SetRevealed, que só
        // chega quando o player entra no raio da Visão Nocturna).
        if (playerCollider == null)
        {
            var playerT = PlayerLocator.Find();
            if (playerT != null)
                playerCollider = playerT.GetComponent<Collider2D>() ?? playerT.GetComponentInChildren<Collider2D>();
        }

        TryApplyPlayerCollision();
    }

    /// <summary>
    /// Activa/desactiva a revelação. 'player' é usado para controlar a
    /// colisão entre os colliders deste objecto e o player (pode ser null —
    /// nesse caso só o fade visual é aplicado, mantendo o estado de colisão
    /// já calculado em Start/SetRevealed anteriores).
    /// </summary>
    public void SetRevealed(bool revealed, Collider2D player = null)
    {
        if (player != null) playerCollider = player;

        IsRevealed = revealed;
        targetAlpha = revealed ? visibleAlpha : 0f;

        // Invisível -> sempre intangível. Revelado -> intangível só se
        // "temColisaoAoRevelar" estiver desactivado (objecto "fantasma").
        desiredIgnore = !revealed || !temColisaoAoRevelar;

        TryApplyPlayerCollision();
    }

    /// <summary>
    /// Aplica "desiredIgnore" ao(s) collider(es) via Physics2D.IgnoreCollision.
    /// Se a colisão estiver a ser REACTIVADA (desiredIgnore=false) e o player
    /// estiver sobreposto a este objecto nesse instante, adia a reactivação
    /// (Update tenta de novo a cada frame) para não causar um "pop" físico.
    /// </summary>
    private void TryApplyPlayerCollision()
    {
        if (playerCollider == null || colliders == null || colliders.Length == 0) return;
        if (desiredIgnore == ignoringPlayerCollision) return;

        if (!desiredIgnore && IsOverlappingPlayer())
            return; // adia até deixarem de se sobrepor

        foreach (var col in colliders)
        {
            if (col == null) continue;
            Physics2D.IgnoreCollision(col, playerCollider, desiredIgnore);
        }

        ignoringPlayerCollision = desiredIgnore;
    }

    private bool IsOverlappingPlayer()
    {
        foreach (var col in colliders)
        {
            if (col == null) continue;
            if (col.IsTouching(playerCollider)) return true;
        }
        return false;
    }

    private void Update()
    {
        // Reactivação de colisão adiada (ver TryApplyPlayerCollision).
        if (desiredIgnore != ignoringPlayerCollision)
            TryApplyPlayerCollision();

        if (spriteRenderer == null) return;

        var c = spriteRenderer.color;
        if (Mathf.Approximately(c.a, targetAlpha)) return;

        c.a = Mathf.MoveTowards(c.a, targetAlpha, fadeSpeed * Time.deltaTime);
        spriteRenderer.color = c;
    }

    private void OnDisable()
    {
        // Garante que não fica colisão ignorada permanentemente se o objecto
        // for desactivado a meio (ex: troca de cena) — restaura colisão normal.
        if (playerCollider != null && colliders != null)
        {
            foreach (var col in colliders)
            {
                if (col == null) continue;
                Physics2D.IgnoreCollision(col, playerCollider, false);
            }
        }

        ignoringPlayerCollision = false;
        desiredIgnore = true;
    }
}
